// @vitest-environment node
/**
 * SPEC-039: acciones por pregunta en el servicio del asistente (main) —
 * descartar/marcar respondida (resolveAssistantItem) también sobre ancladas,
 * análisis inmediato en background de 'answered' (con guard in-flight y gate
 * de límite de coste SPEC-021 intactos), no-ops silenciosos, supresión de
 * candidatas casi idénticas a descartadas/respondidas (métrica SPEC-037),
 * sección nueva del mensaje de usuario, questionOutcomes en el summary /
 * transcript.json / entrevista al parar y regresión de SPEC-021/023/036.
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-016/021/036/037/038 (SDK y Deepgram mockeados con clases de
 * error espejo, store/repository y transcriptionService REALES, fake timers
 * solo de Date).
 */
import { mkdtempSync, readFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import {
  MIN_INTERVAL_MS,
  resolveAssistantItem,
  setAssistantPinned,
  startAssistant,
  stopAssistant,
  triggerAssistantMaintenance
} from '../../../src/main/assistantService'
import { computeCostUsd } from '../../../src/main/aiCost'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import {
  persistTranscript,
  resetTranscription,
  startTranscription
} from '../../../src/main/transcriptionService'
import type {
  AssistantQueue,
  AssistantSessionSummary,
  AssistantUpdateEvent
} from '../../../src/renderer/src/types/assistant'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    dgInstances: [] as unknown[],
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.dgInstances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

interface FakeConnection {
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
}

/** Parámetros relevantes de una llamada create del asistente. */
interface CreateParams {
  system: unknown
  messages: Array<{ role: string; content: string }>
}

function createCall(index: number): CreateParams {
  return harness.create.mock.calls[index][0] as CreateParams
}

/**
 * Respuesta del SDK con bloque thinking + bloque text (el JSON va en text) y
 * usage medible (SPEC-021): el gate de límite necesita un coste de sesión > 0.
 */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    usage: { input_tokens: 1000, output_tokens: 500 },
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

function analysisPayload(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: [],
    objectivesMet: [],
    resolvedQueueIndexes: [],
    ...overrides
  }
}

function createSender(): { sender: WebContents; send: ReturnType<typeof vi.fn> } {
  const send = vi.fn()
  const senderLike = {
    isDestroyed: (): boolean => false,
    send
  }
  return { sender: senderLike as unknown as WebContents, send }
}

function assistantEvents(send: ReturnType<typeof vi.fn>): AssistantUpdateEvent[] {
  return send.mock.calls
    .filter((call) => call[0] === 'assistant:update')
    .map((call) => call[1] as AssistantUpdateEvent)
}

const BASE_TIME_MS = 1_000_000_000

let send: ReturnType<typeof vi.fn>
let connection: FakeConnection
let interviewId = ''
let lineCounter = 0
let analysisCount = 0

/** Inyecta una línea final por la vía pública (transcripción real mockeada). */
function feedFinal(): void {
  lineCounter += 1
  connection.callbacks.onResult({
    channelIndex: lineCounter % 2,
    transcript: `Línea de conversación ${lineCounter}`,
    isFinal: true,
    startSeconds: lineCounter,
    durationSeconds: 1,
    speaker: 0
  })
}

/** Último estado de la cola emitido por main (fuente de verdad del renderer). */
function lastQueue(): AssistantQueue {
  const queue = assistantEvents(send).at(-1)?.queue
  if (queue === undefined) {
    throw new Error('sin eventos del asistente todavía')
  }
  return queue
}

function pendingQuestions(): string[] {
  return lastQueue().pending.map((item) => item.suggestedQuestion)
}

/** Arranca transcripción + asistente sobre una entrevista con objetivos y guión. */
function startSession(): void {
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Entrevista con acciones por pregunta'
  })
  interviewId = interview.id
  repository.updateInterview(interview.id, {
    objectives: ['Objetivo cero', 'Objetivo uno'],
    scriptMarkdown: '# Guión de la entrevista'
  })

  const transcriptionSender = createSender()
  startTranscription(transcriptionSender.sender)
  connection = harness.dgInstances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()

  const assistantSender = createSender()
  send = assistantSender.send
  startAssistant(assistantSender.sender, interview.id)
}

/**
 * Ejecuta UN análisis completo por los disparadores de SPEC-016: avanza la
 * ventana de 20 s si no es el primero, inyecta 3 líneas finales y espera
 * analyzing→active.
 */
async function analyze(overrides: Record<string, unknown> = {}): Promise<void> {
  analysisCount += 1
  const expectedCalls = harness.create.mock.calls.length + 1
  const eventsBefore = assistantEvents(send).length
  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload(overrides)))
  if (analysisCount > 1) {
    vi.setSystemTime(BASE_TIME_MS + (analysisCount - 1) * (MIN_INTERVAL_MS + 1000))
  }
  feedFinal()
  feedFinal()
  feedFinal()
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(expectedCalls))
  await vi.waitFor(() => {
    const events = assistantEvents(send)
    expect(events.length).toBeGreaterThanOrEqual(eventsBefore + 2)
    expect(events.at(-1)?.state).toBe('active')
  })
}

/**
 * Marca respondida una pregunta y espera la llamada de MANTENIMIENTO
 * INMEDIATA que dispara (SPEC-039, adaptada al split de la revisión de coste
 * 2026-07): sin avanzar el reloj ni inyectar líneas nuevas — la inmediatez
 * (sin material nuevo mínimo ni intervalo) es parte de lo verificado.
 */
async function resolveAnswered(
  itemId: string,
  overrides: Record<string, unknown> = {}
): Promise<void> {
  const expectedCalls = harness.create.mock.calls.length + 1
  const eventsBefore = assistantEvents(send).length
  harness.create.mockResolvedValueOnce(
    sdkResponse({ resolvedQueueIndexes: [], objectivesMet: [], ...overrides })
  )
  resolveAssistantItem(itemId, 'answered')
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(expectedCalls))
  await vi.waitFor(() => {
    // 2 eventos: la re-emisión de la retirada manual + el del mantenimiento
    expect(assistantEvents(send).length).toBeGreaterThanOrEqual(eventsBefore + 2)
  })
}

const TOOL_QUESTION = '¿Cuánto pagasteis por la última herramienta que comprasteis?'
const TOOL_QUESTION_VARIANT = '¿Y cuánto pagasteis por esa última herramienta que comprasteis?'

beforeEach(() => {
  vi.clearAllMocks()
  harness.dgInstances.length = 0
  lineCounter = 0
  analysisCount = 0
  vi.useFakeTimers({ toFake: ['Date'] })
  vi.setSystemTime(BASE_TIME_MS)
  initStore(mkdtempSync(join(tmpdir(), 'maurya-question-actions-')))
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
  process.env['DEEPGRAM_API_KEY'] = 'dg-test'
})

afterEach(() => {
  stopAssistant()
  resetTranscription()
  vi.useRealTimers()
  delete process.env['ANTHROPIC_API_KEY']
  delete process.env['DEEPGRAM_API_KEY']
})

describe('assistantService (acciones por pregunta SPEC-039)', () => {
  describe('manual discard and answer (service)', () => {
    // SPEC-039 · AC-05 (descartar: sale de la cola, se registra y sin llamada al LLM)
    it('removes a discarded question from the queue, records it in the session and emits the update without any LLM call', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      const itemId = lastQueue().pending[0].id
      const eventsBefore = assistantEvents(send).length

      resolveAssistantItem(itemId, 'discarded')

      // Re-emisión inmediata con la cola mutada y estado derivado (idle: vacía)
      const events = assistantEvents(send)
      expect(events).toHaveLength(eventsBefore + 1)
      expect(events.at(-1)?.state).toBe('idle')
      expect(events.at(-1)?.queue).toEqual({ pending: [], pinned: [] })
      // Sin ninguna llamada al LLM más allá de la que encoló la pregunta
      expect(harness.create).toHaveBeenCalledTimes(1)
      // Registrada como descartada de la sesión
      expect(stopAssistant()?.questionOutcomes).toEqual([
        { question: TOOL_QUESTION, outcome: 'discarded' }
      ])
    })

    // SPEC-039 · AC-06 (la acción manual sí retira ancladas, con ambos outcomes)
    it('lets the manual action remove pinned questions with both discarded and answered outcomes', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      const firstId = lastQueue().pending[1].id // uno (la más antigua)
      const secondId = lastQueue().pending[0].id // dos
      setAssistantPinned(firstId, true)
      setAssistantPinned(secondId, true)
      expect(lastQueue().pinned).toHaveLength(2)

      resolveAssistantItem(firstId, 'discarded')
      expect(lastQueue().pinned.map((item) => item.suggestedQuestion)).toEqual(['¿Pregunta dos?'])

      // 'answered' sobre la otra anclada: sale también (el mantenimiento
      // inmediato no repone nada: no produce candidatas, cola limpia)
      await resolveAnswered(secondId)
      expect(lastQueue().pinned).toEqual([])
      expect(pendingQuestions()).toEqual([])
      expect(stopAssistant()?.questionOutcomes).toEqual([
        { question: '¿Pregunta uno?', outcome: 'discarded' },
        { question: '¿Pregunta dos?', outcome: 'answered' }
      ])
    })

    // SPEC-039 · AC-07 (answered sin vuelo ni pausa: UNA llamada inmediata en
    // background — de MANTENIMIENTO tras la revisión de coste 2026-07)
    it('fires one immediate background maintenance call on answered whose objectivesMet updates the live tracking', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      const itemId = lastQueue().pending[0].id

      // Sin avanzar el reloj ni inyectar líneas: la llamada es inmediata
      // (sin esperar a los disparadores de 3 líneas / 20 s ni al timer de 30 s)
      await resolveAnswered(itemId, { objectivesMet: [1] })

      expect(harness.create).toHaveBeenCalledTimes(2)
      const last = assistantEvents(send).at(-1)
      // El objectivesMet del mantenimiento inmediato actualiza el seguimiento
      expect(last?.objectivesMet).toEqual([1])
      // La respondida salió de la cola (retirada manual)
      expect(last?.queue.pending).toEqual([])
    })

    // SPEC-039 · AC-08 (guard in-flight intacto — ahora es el guard PROPIO del
    // mantenimiento: un mantenimiento en vuelo bloquea la llamada extra)
    it('does not fire an extra call when answered arrives with a maintenance call already in flight', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      const itemId = lastQueue().pending[0].id

      // Mantenimiento en vuelo: promesa diferida controlada por el test
      let resolveSdk: ((value: unknown) => void) | null = null
      harness.create.mockImplementationOnce(
        () =>
          new Promise((resolve) => {
            resolveSdk = resolve
          })
      )
      triggerAssistantMaintenance()
      await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(2))

      resolveAssistantItem(itemId, 'answered')

      // La pregunta sale igualmente sin llamada extra (guard maintenanceInFlight)
      expect(assistantEvents(send).at(-1)?.queue.pending).toEqual([])
      expect(harness.create).toHaveBeenCalledTimes(2)

      if (resolveSdk === null) {
        throw new Error('la llamada en vuelo no llegó a iniciarse')
      }
      ;(resolveSdk as (value: unknown) => void)(
        sdkResponse({ resolvedQueueIndexes: [], objectivesMet: [0] })
      )
      await vi.waitFor(() => expect(assistantEvents(send).at(-1)?.objectivesMet).toEqual([0]))
      // Tampoco después del aterrizaje: siguen siendo 2 llamadas en total
      expect(harness.create).toHaveBeenCalledTimes(2)
    })

    // SPEC-039 · AC-09 (gate de límite SPEC-021 intacto: pausado → sin llamada)
    it('removes the answered question without any LLM call while the assistant is paused by cost limit', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION }) // coste de sesión > 0
      const itemId = lastQueue().pending[0].id
      // El límite se lee en cada evaluación: ya alcanzado por el 1er análisis
      repository.setAiCostSettings({ limitUsd: 0.01 })

      resolveAssistantItem(itemId, 'answered')

      // Sale de la cola y el gate pausa SIN llamada al LLM
      expect(harness.create).toHaveBeenCalledTimes(1)
      const last = assistantEvents(send).at(-1)
      expect(last?.state).toBe('paused')
      expect(last?.pauseLimitUsd).toBe(0.01)
      expect(last?.queue.pending).toEqual([])
      expect(stopAssistant()?.questionOutcomes).toEqual([
        { question: TOOL_QUESTION, outcome: 'answered' }
      ])
    })

    // SPEC-039 · AC-10 (id inexistente o sin sesión: no-op silencioso, patrón setPinned)
    it('ignores silently an unknown item id and a resolve without an active session', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      const eventsBefore = assistantEvents(send).length

      resolveAssistantItem('id-inexistente', 'discarded')
      resolveAssistantItem('id-inexistente', 'answered')

      // Ni eventos nuevos, ni llamadas, ni cambios en la cola
      expect(assistantEvents(send)).toHaveLength(eventsBefore)
      expect(harness.create).toHaveBeenCalledTimes(1)
      expect(pendingQuestions()).toEqual([TOOL_QUESTION])
      // El histórico manual queda vacío
      expect(stopAssistant()?.questionOutcomes).toEqual([])

      // Sin sesión activa: no lanza y no llama
      expect(() => resolveAssistantItem('cualquiera', 'answered')).not.toThrow()
      expect(harness.create).toHaveBeenCalledTimes(1)
    })
  })

  describe('suppression and prompt over discarded/answered', () => {
    // SPEC-039 · AC-11 (candidata casi idéntica a una descartada → suprimida)
    it('suppresses a later candidate almost identical to a discarded question', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      resolveAssistantItem(lastQueue().pending[0].id, 'discarded')
      expect(pendingQuestions()).toEqual([])

      // Candidata casi idéntica (métrica SPEC-037) a la descartada
      await analyze({ suggestedQuestion: TOOL_QUESTION_VARIANT })

      expect(pendingQuestions()).toEqual([])
      // La suprimida no cuenta como sugerencia de la sesión
      expect(stopAssistant()?.suggestionCount).toBe(1)
    })

    // SPEC-039 · AC-12 (candidata casi idéntica a una respondida → suprimida;
    // revisado: el mantenimiento inmediato no produce candidatas — la
    // supresión se verifica sobre el SIGUIENTE análisis interactivo)
    it('suppresses a later candidate almost identical to an answered question', async () => {
      startSession()
      await analyze({ suggestedQuestion: TOOL_QUESTION })
      await resolveAnswered(lastQueue().pending[0].id)

      // Un análisis posterior devuelve una casi idéntica a la respondida
      await analyze({ suggestedQuestion: TOOL_QUESTION_VARIANT })

      expect(pendingQuestions()).toEqual([])
      expect(stopAssistant()?.suggestionCount).toBe(1)
    })

    // SPEC-039 · AC-13 (sección nueva del MENSAJE DE USUARIO con la instrucción)
    it('includes the discarded and answered questions with the do-not-repeat instruction in the user message only', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      // Sin histórico manual la sección NO existe (idéntico al prompt anterior)
      expect(createCall(0).messages[0].content).not.toContain(
        'Preguntas ya descartadas o respondidas'
      )
      expect(createCall(1).messages[0].content).not.toContain(
        'Preguntas ya descartadas o respondidas'
      )

      resolveAssistantItem(lastQueue().pending[1].id, 'discarded') // uno
      await resolveAnswered(lastQueue().pending[0].id) // dos → mantenimiento (3ª llamada)
      await analyze({ suggestedQuestion: '¿Pregunta tres?' }) // 4ª llamada

      // El análisis interactivo posterior lleva la lista (descartadas primero)
      expect(createCall(3).messages[0].content).toContain(
        '## Preguntas ya descartadas o respondidas por el entrevistador (NO las repitas ni propongas variantes)\n- ¿Pregunta uno?\n- ¿Pregunta dos?'
      )
      // La lista viaja SOLO en el mensaje de usuario, nunca en el prefijo
      // cacheado ni en la llamada de mantenimiento
      expect(JSON.stringify(createCall(3).system)).not.toContain('descartadas')
      expect(createCall(2).messages[0].content).not.toContain(
        'Preguntas ya descartadas o respondidas'
      )
    })
  })

  describe('persistence on recording stop', () => {
    // SPEC-039 · AC-14 (questionOutcomes en el summary → transcript.json + entrevista)
    it('returns questionOutcomes in the stop summary and persists them into transcript.json and into the interview', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      resolveAssistantItem(lastQueue().pending[1].id, 'discarded')
      await resolveAnswered(lastQueue().pending[0].id)

      // stopAssistant: descartadas primero, respondidas después (orden del contrato)
      const summary = stopAssistant()
      expect(summary?.questionOutcomes).toEqual([
        { question: '¿Pregunta uno?', outcome: 'discarded' },
        { question: '¿Pregunta dos?', outcome: 'answered' }
      ])

      // El campo assistant del transcript.json incluye questionOutcomes
      // (persistTranscript escribe el summary tal cual, camino de recording:stop)
      const dir = mkdtempSync(join(tmpdir(), 'maurya-question-actions-transcript-'))
      const { transcriptPath } = persistTranscript(join(dir, 'entrevista.wav'), summary)
      if (transcriptPath === null) {
        throw new Error('persistTranscript devolvió null con líneas finales recibidas')
      }
      const persisted = JSON.parse(readFileSync(transcriptPath, 'utf8')) as {
        assistant: AssistantSessionSummary | null
      }
      expect(persisted.assistant?.questionOutcomes).toEqual(summary?.questionOutcomes)

      // La entrevista persiste las MISMAS entradas (repository, camino recording:stop)
      if (summary === null) {
        throw new Error('el asistente estaba activo: el summary no puede ser null')
      }
      repository.setInterviewQuestionOutcomes(interviewId, summary.questionOutcomes)
      expect(repository.getInterview(interviewId).questionOutcomes).toEqual(
        summary.questionOutcomes
      )
    })

    // SPEC-039 · AC-15 (sin acciones manuales: questionOutcomes vacío y el resto intacto)
    it('keeps questionOutcomes empty and suggestionCount/usage unchanged without manual actions', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })

      const summary = stopAssistant()
      expect(summary?.questionOutcomes).toEqual([])
      expect(summary?.suggestionCount).toBe(1)
      // Revisión de coste 2026-07: el interactivo corre en Haiku por defecto
      // y el usage viaja con su desglose byTask
      expect(summary?.usage).toEqual({
        calls: 1,
        inputTokens: 1000,
        outputTokens: 500,
        estimatedCostUsd: computeCostUsd('claude-haiku-4-5', 1000, 500),
        byTask: {
          assistantInteractive: {
            calls: 1,
            inputTokens: 1000,
            outputTokens: 500,
            cacheWriteTokens: 0,
            cacheReadTokens: 0,
            estimatedCostUsd: computeCostUsd('claude-haiku-4-5', 1000, 500)
          }
        }
      })
    })
  })

  describe('regression (SPEC-021/023/036 invariants)', () => {
    // SPEC-039 · AC-23 (prefijo cacheado byte-idéntico con acciones manuales
    // entre medias; el mantenimiento tiene su PROPIO prefijo, también estable)
    it('keeps the system blocks byte-identical across analyses with manual actions in between', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      resolveAssistantItem(lastQueue().pending[0].id, 'discarded')
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      await resolveAnswered(lastQueue().pending[0].id) // mantenimiento (3ª llamada)
      await analyze({ suggestedQuestion: '¿Pregunta cuatro?' }) // 4ª llamada

      expect(JSON.stringify(createCall(1).system)).toBe(JSON.stringify(createCall(0).system))
      expect(JSON.stringify(createCall(3).system)).toBe(JSON.stringify(createCall(0).system))
    })

    // SPEC-039 · AC-24 (suggestionCount sigue contando solo candidatas aceptadas)
    it('keeps suggestionCount counting only accepted candidates after manual resolutions', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })

      resolveAssistantItem(lastQueue().pending[1].id, 'discarded') // uno
      await resolveAnswered(lastQueue().pending[0].id) // dos → mantenimiento
      // Un análisis posterior devuelve una casi idéntica a la respondida: suprimida
      await analyze({ suggestedQuestion: '  pregunta dos ' })

      // Solo cuentan las 2 aceptadas; ni las acciones ni la suprimida suman
      expect(stopAssistant()?.suggestionCount).toBe(2)
    })

    // SPEC-039 · AC-25 (anclar/desanclar de SPEC-036 intactos)
    it('keeps pin and unpin behaviour intact: move to pinned and return to the front of pending', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos?' })
      const pinnedId = lastQueue().pending[1].id // uno (la más antigua)

      setAssistantPinned(pinnedId, true)
      expect(lastQueue().pinned.map((item) => item.suggestedQuestion)).toEqual(['¿Pregunta uno?'])
      expect(pendingQuestions()).toEqual(['¿Pregunta dos?'])

      setAssistantPinned(pinnedId, false)
      expect(lastQueue().pinned).toEqual([])
      // La desanclada vuelve al FRENTE de pendientes
      expect(pendingQuestions()).toEqual(['¿Pregunta uno?', '¿Pregunta dos?'])
      // La gestión de la cola no dispara llamadas al LLM
      expect(harness.create).toHaveBeenCalledTimes(2)
    })
  })
})
